import com.yottastudios.ns.collabspace.user.service.*;
import com.yottastudios.ns.collabspace.user.vo.TeamInfoVo;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Configuration;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.scheduling.annotation.Scheduled;

import java.util.*;
import java.util.concurrent.TimeUnit;
import java.util.function.Function;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.AIO_TEAM_OPERATE_EXCHANGE;
import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.AIO_TEAM_OPERATE_KEY;

@Slf4j
@Configuration(proxyBeanMethods = false)
public class MattermostUserSyncTask {

    @Resource
    private MattermostUserFeignClient mattermostUserFeignClient;

    @Resource
    private MattermostGroupFeignClient mattermostGroupFeignClient;

    @Resource
    private IUserProjectService userProjectService;

    @Resource
    private IUserProjectTeamRelService userProjectTeamRelService;

    @Resource
    private IUserTeamService userTeamService;

    @Resource
    private IUserTeamUserRelService userTeamUserRelService;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private UserTeamUpdateManager userTeamUpdateManager;

    @Resource
    private AffineHttpClientService affineHttpClientService;

    @Resource
    private IViewUserTeamRelService viewUserTeamRelService;

    @Resource
    private RabbitMqSender rabbitMqSender;

    @Resource
    private MattermostProperties mattermostProperties;

    @Resource
    private ConstProperties constProperties;

    @Resource
    private RedisTemplate<String, String> redisTemplate;

    @Resource
    private IAuthService authService;

    @Value("${mm-test-only-tag:false}")
    private boolean mmTestOnlyOnlyTag;

    @Value("${mm-test-filter-tag:false}")
    private boolean mmTestFilterTag;

    private static  final Long SPEC_OPERATOR = -1L;


    @Scheduled(cron = "0 0/1 * * * ?")
    public void schedulerJobTask() {

        log.info("Scheduler task started");

        boolean internalNetwork = constProperties.isInternalNetwork();
        if(!internalNetwork && !mmTestOnlyOnlyTag)
            return;

        boolean mirror = constProperties.isMirror();
        if(mirror)
            return;

        log.info("Scheduler task initiated");


        Long operator = -1L;

        List<UserSimpleInfoVo> allExistUsers = apitableGrpcClientService.getAllExistUsers(operator);
        Map<String, Long> allUserEmailMap = new HashMap<>();
        Map<Long, String> allUserIdMap = new HashMap<>();
        Map<String, UserSimpleInfoVo> existUserMap = allExistUsers.stream().filter(x->StringUtils.isNotBlank(x.getEmail()) && x.getEmail().endsWith("@yottastudios.com")).
                collect(Collectors.toMap(UserSimpleInfoVo::getEmail,Function.identity(),(v1,v2)->v2));
        Set<String> departUserEmails = new HashSet<>();
        Set<String> recoverUserEmails = new HashSet<>();
        List<Long> updateMmSyncUserIds = new ArrayList<>();
        List<Long> inTeamUserIds = new ArrayList<>();

        //手动添加用户
        List<String> manualUserEmails = new ArrayList<>(allExistUsers.stream().filter(x -> StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
                map(UserSimpleInfoVo::getEmail).toList());
        Map<Long, UserSimpleInfoVo> manualUserMap = allExistUsers.stream().filter(x->StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
                collect(Collectors.toMap(UserSimpleInfoVo::getId,Function.identity()));
        List<Long> manualUserIds = new ArrayList<>(allExistUsers.stream().filter(x -> StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
                map(UserSimpleInfoVo::getId).toList());
        log.info("manualUserEmails1 size: {}", manualUserEmails.size());



        List<UserProjectEntity> mmProjectList = userProjectService.list().stream().filter(x -> StringUtils.isNotBlank(x.getMattermostId())).toList();
        if(CollectionUtils.isEmpty(mmProjectList)) return;

        for (UserProjectEntity project : mmProjectList) {

            // false不代表接口没变化... Boolean cacheUpdateKey=false;

            Long projectId = project.getId();

            List<MattermostUserResp> mmUserList = getMMUserList(project.getMattermostId());
            //过滤掉并过滤出要删除的用户

            Set<String> contractorUserEmails = new HashSet<>();
            List<MattermostGroupResp> mmUsersWithTeam = getUsersWithTeam(project.getMattermostId());
            List<MattermostGroupResp> contractorTeam =
                    mmUsersWithTeam.stream().filter(t -> t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
            if(CollectionUtils.isNotEmpty(contractorTeam)){
                contractorTeam.forEach(ct->{
                    List<MattermostGroupResp.UserSimpleResp> users = ct.getUsers();
                    if(CollectionUtils.isNotEmpty(users))
                        users.forEach(user-> contractorUserEmails.add(user.getEmail()));
                });
            }
            if(CollectionUtils.isNotEmpty(contractorUserEmails)){
                mmUserList = mmUserList.stream().filter(x->!contractorUserEmails.contains(x.getEmail())).toList();
                departUserEmails.addAll(contractorUserEmails);
            }
            mmUsersWithTeam=mmUsersWithTeam.stream().filter(t -> !t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();

            Map<String, MattermostUserResp> mmUserMap = mmUserList.stream().collect(Collectors.toMap(MattermostUserResp::getEmail, Function.identity()));
            //add User
            mmUserMap.forEach((k, v) -> {
                if(!Validator.isEmail(k)) return;
                if(allUserEmailMap.containsKey(k)) return;
                if (existUserMap.containsKey(k)){
                    UserSimpleInfoVo userSimpleInfoVo = existUserMap.get(k);
                    allUserEmailMap.put(k, userSimpleInfoVo.getId());
                    allUserIdMap.put(userSimpleInfoVo.getId(),k);
                    if(UserStatusEnum.DISABLE.getValue().equals(userSimpleInfoVo.getStatus())){
                        recoverUserEmails.add(k);
                    } else if(manualUserEmails.contains(k)){
                        log.info("manualUserEmails updateIn");
                        updateMmSyncUserIds.add(userSimpleInfoVo.getId());
                        manualUserEmails.remove(k);
                        manualUserMap.remove(userSimpleInfoVo.getId());
                        manualUserIds.remove(userSimpleInfoVo.getId());
                    }

                } else {
                    Long registerId = null;
                    try{
                        registerId = authService.register(v.getEmail(), StringUtils.isNotBlank(v.getNickname()) ? v.getNickname() : v.getUsername(), RandomExtendUtil.randomString(8),true);

                    }catch (Exception e){
                        log.error("schedulerJobTask register error : {}",k,e);
                    }
                    if(null!=registerId){
                        allUserEmailMap.put(k,registerId);
                        allUserIdMap.put(registerId,k);
                    }
                }
            });


            Map<String, UserTeamEntity> teamMMMap = new HashMap<>();
            Map<Long, List<UserTeamUserRelEntity>> teamUserRelGroup = new HashMap<>();
            List<UserTeamEntity> errorTeamList = new ArrayList<>();
            Long commonRelTeamId = null;
            List<UserProjectTeamRelEntity> teamRelList = userProjectTeamRelService.listByProjectId(projectId);
            if(CollectionUtils.isNotEmpty(teamRelList)){
                UserProjectTeamRelEntity commonRel = teamRelList.stream().filter(x -> BinaryOperationEnum.ON.getValue().equals(x.getIsCommon())).findFirst().orElse(null);
                if(null!=commonRel)
                    commonRelTeamId =commonRel.getTeamId();

                List<Long> teamIds = teamRelList.stream().map(UserProjectTeamRelEntity::getTeamId).toList();
                List<UserTeamEntity> userTeamList = userTeamService.listByIds(teamIds);

                teamMMMap = userTeamList.stream().filter(x->StringUtils.isNotBlank(x.getMattermostId())).collect(Collectors.toMap(UserTeamEntity::getMattermostId, Function.identity()));
                Long finalCommonRelTeamId = commonRelTeamId;
                errorTeamList = userTeamList.stream().filter(x -> (StringUtils.isBlank(x.getMattermostId()) && !x.getId().equals(finalCommonRelTeamId))
                        && TeamDataSourceType.MATTERMOST.getId().equals(x.getDataSource())).toList();
                List<UserTeamUserRelEntity> userTeamRelList = userTeamUserRelService.listInTeamIds(teamIds);
                if(CollectionUtils.isNotEmpty(userTeamList)){
                    teamUserRelGroup = userTeamRelList.stream().collect(Collectors.groupingBy(UserTeamUserRelEntity::getTeamId));
                }
            }

            mmUsersWithTeam=mmUsersWithTeam.stream().filter(x->StringUtils.isNotBlank(x.getGroupid())).toList();
            for (MattermostGroupResp mmTeam : mmUsersWithTeam) {
                String groupId = mmTeam.getGroupid();
                Long teamId;
                if(teamMMMap.containsKey(groupId)){
                    UserTeamEntity userTeamEntity = teamMMMap.get(groupId);
                    teamId=userTeamEntity.getId();
                    if(!userTeamEntity.getTeamName().equals(mmTeam.getDisplaygroupname())){
                        //update team name
                        userTeamEntity.setTeamName(mmTeam.getDisplaygroupname());
                        userTeamService.updateById(userTeamEntity);
                    }
                    //team user set
                    List<MattermostGroupResp.UserSimpleResp> mmTeamUsers = mmTeam.getUsers();
                    List<String> mmUserEmail = mmTeamUsers.stream().map(MattermostGroupResp.UserSimpleResp::getEmail).toList();
                    List<Long> mmUserIds = new ArrayList<>();
                    for (String e : mmUserEmail) {
                        if (allUserEmailMap.containsKey(e))
                            mmUserIds.add(allUserEmailMap.get(e));
                    }
                    inTeamUserIds.addAll(mmUserIds);
                    List<UserTeamUserRelEntity> curUserRelList = teamUserRelGroup.get(teamId);

                    List<Long> addUserIds;
                    List<Long> updateUserIds = new ArrayList<>();
                    List<Long> delUserIds = new ArrayList<>();
                    if(CollectionUtils.isNotEmpty(curUserRelList)){
                        List<Long> curUserRelIds = curUserRelList.stream().map(UserTeamUserRelEntity::getUserId).toList();
                        addUserIds = mmUserIds.stream().filter(x->!curUserRelIds.contains(x)).toList();
                        curUserRelList.forEach(x->{
                            if(!mmUserIds.contains(x.getUserId())){
                                UserSimpleInfoVo userSimpleInfoVo = manualUserMap.get(x.getUserId());
                                if(null==userSimpleInfoVo){
                                    delUserIds.add(x.getUserId());
                                }
                            }
                        });
                        curUserRelList.forEach(x->{
                            if(mmUserIds.contains(x.getUserId()))
                                updateUserIds.add(x.getUserId());
                        });
                    }else{
                        addUserIds=mmUserIds;
                    }
                    //add user
                    if(CollectionUtils.isNotEmpty(addUserIds)){

                        List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
                        addUserIds.forEach(u -> userRelEntities.add(UserTeamUserRelEntity.builder().teamId(teamId).userId(u).build()));
                        userTeamUserRelService.saveBatch(userRelEntities);

                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(addUserIds, List.of(teamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
                        log.info("Sending object to exchange: {}, routeKey: {},message:{}", AIO_TEAM_OPERATE_EXCHANGE, AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                    }

                    //delete user
                    if(CollectionUtils.isNotEmpty(delUserIds)){
                        userTeamUserRelService.delByTeamIdInUserIds(teamId,delUserIds);
                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(delUserIds, List.of(teamId), AioTeamOperateTypeEnum.DELETE_USER.getValue(),SPEC_OPERATOR);
                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                    }

                    if(CollectionUtils.isNotEmpty(updateUserIds)){
                        userTeamUserRelService.setInTeam(teamId,updateUserIds);
                    }

                    //删除空组
                    if (CollectionUtils.isEmpty(addUserIds)) {
                        if (CollectionUtils.isEmpty(curUserRelList)) {
                            userTeamUserRelService.delByTeamId(teamId);
                            viewUserTeamRelService.delByTeamId(teamId);
                            userTeamUpdateManager.deleteTeam(teamId);
                        } else {

                            if (CollectionUtils.isNotEmpty(delUserIds) ) {
                                //比较curUserRelList是先过滤出isMmSync的
                                int curSize=curUserRelList.size();
                                if(CollectionUtils.isNotEmpty(curUserRelList)){
                                    curSize = curUserRelList.stream().filter(x->!manualUserIds.contains(x.getUserId())).toList().size();
                                }
                                if(delUserIds.size() == curSize){
                                    userTeamUserRelService.delByTeamId(teamId);
                                    viewUserTeamRelService.delByTeamId(teamId);
                                    userTeamUpdateManager.deleteTeam(teamId);
                                }

                            }
                        }
                    }

                }else{
                    List<MattermostGroupResp.UserSimpleResp> mmTeamUsers = mmTeam.getUsers();
                    List<String> mmUserEmail = mmTeamUsers.stream().map(MattermostGroupResp.UserSimpleResp::getEmail).toList();
                    List<Long> mmUserIds = new ArrayList<>();
                    for (String e : mmUserEmail) {
                        if (allUserEmailMap.containsKey(e))
                            mmUserIds.add(allUserEmailMap.get(e));
                    }
                    if(CollectionUtils.isNotEmpty(mmUserIds)){
                        //add team
                        TeamInfoVo newTeam = userTeamUpdateManager.createTeamForSync(new TeamCreateRo(mmTeam.getDisplaygroupname(), projectId,groupId,BinaryOperationEnum.OFF.getValue(), TeamDataSourceType.MATTERMOST.getId()));
                        teamId = newTeam.getId();

                        List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
                        mmUserIds.forEach(u -> userRelEntities.add(UserTeamUserRelEntity.builder().teamId(teamId).userId(u).build()));
                        userTeamUserRelService.saveBatch(userRelEntities);

                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(mmUserIds, List.of(teamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
                        log.info("Sending object to exchange: {}, routeKey: {},message:{}", AIO_TEAM_OPERATE_EXCHANGE, AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                    }

                }

            }

            //delete team
            if(!teamMMMap.isEmpty()){
                List<String> mmIds = mmUsersWithTeam.stream().map(MattermostGroupResp::getGroupid).toList();
                teamMMMap.forEach((k, v) -> {
                    if(!mmIds.contains(k)){
                        userTeamUserRelService.delByTeamId(v.getId());
                        viewUserTeamRelService.delByTeamId(v.getId());
                        userTeamUpdateManager.deleteTeam(v.getId());
                    }
                });
            }
            if(CollectionUtils.isNotEmpty(errorTeamList)){
                errorTeamList.forEach(team -> {
                    userTeamUserRelService.delByTeamId(team.getId());
                    viewUserTeamRelService.delByTeamId(team.getId());
                    userTeamUpdateManager.deleteTeam(team.getId());
                });
            }

            //通用组特殊处理
            List<Long> allUserIds = inTeamUserIds.stream().distinct().toList();
            if(null==commonRelTeamId){
                //add team
                TeamInfoVo commonTeam = userTeamUpdateManager.createTeamForSync(new TeamCreateRo("全部成员", projectId,null,BinaryOperationEnum.ON.getValue(),TeamDataSourceType.MATTERMOST.getId()));
                commonRelTeamId = commonTeam.getId();
                //batch save
                List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
                for (Long u : allUserIds)
                    userRelEntities.add(UserTeamUserRelEntity.builder().teamId(commonRelTeamId).userId(u).build());

                userTeamUserRelService.saveBatch(userRelEntities);

            }else{
                List<UserTeamUserRelEntity> curUserRelList = teamUserRelGroup.get(commonRelTeamId);
                List<Long> addUserIds;
                List<Long> delUserIds = new ArrayList<>();
                if(CollectionUtils.isNotEmpty(curUserRelList)){
                    List<Long> curUserRelIds = curUserRelList.stream().map(UserTeamUserRelEntity::getUserId).toList();
                    addUserIds = allUserIds.stream().filter(x->!curUserRelIds.contains(x)).toList();
                    curUserRelList.forEach(x->{
                        if(!allUserIds.contains(x.getUserId())){
                            UserSimpleInfoVo userSimpleInfoVo = manualUserMap.get(x.getUserId());
                            if(null==userSimpleInfoVo){
                                delUserIds.add(x.getUserId());
                            }
                        }
                    });
                }else{
                    addUserIds=allUserIds;
                }
                //add user
                if(CollectionUtils.isNotEmpty(addUserIds)){

                    List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
                    for (Long u : addUserIds)
                        userRelEntities.add(UserTeamUserRelEntity.builder().teamId(commonRelTeamId).userId(u).build());

                    userTeamUserRelService.saveBatch(userRelEntities);

                    UserTeamOperateMessage messageDto = new UserTeamOperateMessage(addUserIds, List.of(commonRelTeamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
                    rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
                }

                //delete user
                if(CollectionUtils.isNotEmpty(delUserIds)){

                    userTeamUserRelService.delByTeamIdInUserIds(commonRelTeamId,delUserIds);

                    UserTeamOperateMessage messageDto = new UserTeamOperateMessage(delUserIds, List.of(commonRelTeamId), AioTeamOperateTypeEnum.DELETE_USER.getValue(),SPEC_OPERATOR);
                    rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));

                }
            }
        }

        //recover
        if(CollectionUtils.isNotEmpty(recoverUserEmails)){
            recoverUsers(new ArrayList<>(recoverUserEmails));
        }

        //update
        //recover
        if(CollectionUtils.isNotEmpty(updateMmSyncUserIds)){
            log.info("updateMmSyncUserIds size: {}", updateMmSyncUserIds.size());
            apitableGrpcClientService.updateIsMmSyncSourceByUserIds(updateMmSyncUserIds,true);
        }

        //team depart
        log.info("departUserEmails size: {}", departUserEmails.size());
        if(CollectionUtils.isNotEmpty(departUserEmails)){
            List<String> teamDepartUsers = allExistUsers.stream().filter(x -> departUserEmails.contains(x.getEmail()) && UserStatusEnum.NORMAL.getValue().equals(x.getStatus())
                    && !manualUserEmails.contains(x.getEmail())).
                    map(UserSimpleInfoVo::getEmail).toList();
            log.info("teamDepartUsers size: {}", teamDepartUsers.size());
            if(CollectionUtils.isNotEmpty(teamDepartUsers)){
                departUsers(teamDepartUsers);
            }
        }

        //filterToDepart
        Set<String> allMMEmails = allUserEmailMap.keySet();
        List<String> filterToDepartEmails = allExistUsers.stream().filter(x -> !allMMEmails.contains(x.getEmail()) && UserStatusEnum.NORMAL.getValue().equals(x.getStatus())).
                    map(UserSimpleInfoVo::getEmail).toList();
        log.info("filterToDepartEmails size: {}", filterToDepartEmails.size());

        Map<String, UserSimpleInfoVo> allUserEmailToUserMap = allExistUsers.stream()
                .filter(x -> StringUtils.isNotBlank(x.getEmail()))
                .collect(Collectors.toMap(
                        UserSimpleInfoVo::getEmail,
                        Function.identity(),
                        (v1, v2) -> v2
                ));

        // 然后在过滤时使用
        if (CollectionUtils.isNotEmpty(filterToDepartEmails)) {
            filterToDepartEmails = filterToDepartEmails.stream()
                    .filter(x -> {
                        if (StringUtils.isBlank(x) || manualUserEmails.contains(x)) {
                            return false;
                        }

                        UserSimpleInfoVo user = allUserEmailToUserMap.get(x);
                        if (user == null) {
                            log.warn("User email not found: {}", x);
                            return false;
                        }

                        return UserStatusEnum.NORMAL.getValue().equals(user.getStatus());
                    })
                    .toList();
        }

        log.info("filterToDepartEmails final size: {}", filterToDepartEmails.size());
        if(CollectionUtils.isNotEmpty(filterToDepartEmails)&&!mmTestFilterTag){
            departUsers(filterToDepartEmails);
        }

    }

    private List<MattermostUserResp> getMMUserList(String projectId){
        List<MattermostUserResp> allUsers = new ArrayList<>();
        int page = 0;
        boolean hasMore = true;
        int batchSize =100;


        while (hasMore) {
            List<MattermostUserResp> mattermostUsers = mattermostUserFeignClient.getUsers(
                    "Bearer " + mattermostProperties.getReqToken(),
                    page, batchSize,
                    projectId,
                    null, null, null, null, null, null, null, null, null, null, null, null, null, null
            );

            if (CollectionUtils.isEmpty(mattermostUsers) || mattermostUsers.size() < batchSize) {
                hasMore = false;
            }

            allUsers.addAll(mattermostUsers);
            page++;

        }

        try{
            String cacheInfo = JSONUtil.toJsonStr(allUsers);
            String key = RedisConstants.getMMUserKey(projectId);
            long twoHoursInSeconds = 2 * 60 * 60;
            redisTemplate.opsForValue().set(key, cacheInfo, twoHoursInSeconds, TimeUnit.SECONDS);
        }catch (Exception e){
            log.error("MMUserList cache update error",e);
        }


        return allUsers;
    }

    private List<MattermostGroupResp> getUsersWithTeam(String projectId){
        List<MattermostGroupResp> usersWithTeam = mattermostGroupFeignClient.getUsersWithTeam(
                "Bearer " + mattermostProperties.getReqToken(),
                projectId, true
        );
        try{
            String cacheInfo = JSONUtil.toJsonStr(usersWithTeam);
            String key = RedisConstants.getMMUserTeamKey(projectId);
            long twoHoursInSeconds = 2 * 60 * 60;
            redisTemplate.opsForValue().set(key, cacheInfo, twoHoursInSeconds, TimeUnit.SECONDS);
        }catch (Exception e){
            log.error("MMUserTeamList cache update error",e);
        }
        return usersWithTeam;
    }


    public void departUsers(List<String> emails) {

        try {
            apitableGrpcClientService.departUsersInEmails(emails,true);
            affineHttpClientService.deleteUsers(emails.stream().map(x -> UserDeleteRequest.builder().email(x).build()).toList());
        } catch (Exception e) {
            log.error("departUsers:", e);
        }

    }

    public void recoverUsers(List<String> emails) {

        try {
            apitableGrpcClientService.recoverUsersInEmails(emails,true);
            affineHttpClientService.createUsers(
                    emails.stream().map(x -> CreateUserRequest.builder().email(x).userName(EmailUtil.getEmailPrefix(x)).password("123456").build()).toList());
        } catch (Exception e) {
            log.error("recoverUsers:", e);
        }

    }

